ATION_FLAG,F_BUYER_SELLER_IND,F_CLEARED_TRANSACTION_FLAG,F_DVP_FLAG,F_EQUITY_TRADED_FLAG,F_EXCHG_OF_PRINCIPAL,F_EXP_DEFAULTED_FLAG,F_EXP_FUND_CCY_SAME_IND,F_EXP_FX_FUND_CURR_SAME_IND,F_FAILED_TRADE_FLAG,F_GUAR_BY_SOVERIGN_IND,F_LONG_SETTLEMENT_TXN_FLAG,F_MARGINED_TXN_IND,F_MATERIALITY_FLAG,F_OTC_IND,F_PREF_TREATMENT_FLAG,F_QUAL_REF_OBLIG_IND,F_RECIPROCAL_CROSS_HLDG_IND,F_REG_CAP_INVST_IND,F_RW_BY_DISCRETION,F_SECURED_IND,F_SECURITIZED_FLAG,F_SENIOR_CLAIM_FLAG,F_SHORT_POSITION_IND,F_SOLVENCY_IND,F_SPECIFIC_WRONG_WAY_RISK_IND,F_SQUARED_POS_TRADE_IND,F_UNCOND_CANCELLED_EXP_IND,N_ACTUAL_BUSINESS_DAYS,N_ADJUSTED_ELGD_PERCENT,N_BUSINESS_DAYS_LONG_TXN,N_CCF_PERCENT,N_CCF_PERCENT_DRAWN,N_CONTRACT_SIZE,N_FAILED_BUSINESS_DAYS,N_HOLDING_PERIOD,N_INSTR_RESIDUAL_MATURITY,N_LOAD_RUN_ID,N_MIN_HOLDING_PERIOD,N_NO_OF_UNDERLYINGS,N_OTC_DERIVATIVE_MULTIPLIER,N_REMAIN_NO_OF_PMTS_PAY,N_REMARGIN_FREQUENCY,N_REVALUATION_FREQUENCY,N_STD_BUSINESS_DAYS,N_SUPERVISORY_BETA_VALUE,N_VOLATILITY_HAIRCUT,V_PRODUCT_BOOK_CODE,V_CCY_CODE,V_DAY_CONVENTION,V_MARGIN_AGREEMENT_CD,V_OPTION_TYPE,V_OTHER_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_CLEARED_TXN_BANK_ROLE.N_CLEARED_TXN_BANK_ROLE_ID),to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_EXPOSURE_SENIORITY.N_EXP_SENIORITY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_INDUSTRY.N_D_CUST_INDUSTRY_SKEY),to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),to_char(DIM_NETTING_AGREEMENT.N_NETTING_AGREEMENT_SKEY),DIM_PARTY.F_CORE_INVESTMENT_COMPANY_IND,DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),CASE WHEN STG_OPTION_CONTRACTS.f_cleared_transaction_flag = 'Y' THEN 'N' END,Case When STG_OPTION_CONTRACTS.V_CUST_REF_CODE <> STG_OPTION_CONTRACTS.V_CENTRAL_COUNTERPARTY_CODE AND DIM_CLEARED_TXN_BANK_ROLE.V_CLEARED_TXN_BANK_ROLE_CODE ='CM' AND coalesce(STG_OPTION_CONTRACTS.F_CLEARED_TRANSACTION_FLAG,'N') ='Y' Then 'Y' end,STG_OPTION_CONTRACTS.F_ILLIQUID_DERIVATIVES,CASE WHEN COALESCE(STG_UNDERLYING_EXPOSURES.V_CCY_CODE,'MSG') = STG_OPTION_CONTRACTS.V_CCY_CODE THEN 'Y' ELSE 'N' END,CASE  WHEN INTERNAL_ENTITY.V_PARTY_ID IS NOT NULL AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ('FLCS', 'PRCS','FAGR','PRAGR') THEN  'Y' ELSE 'N'   END,CASE WHEN COALESCE(STG_OPTION_CONTRACTS.f_contract_walk_away_ind,'N') = 'Y' THEN 'N' ELSE STG_OPTION_CONTRACTS.f_nettability_flag END,CASE WHEN DIM_EXPOSURE_FIDUCIARY.N_ACCT_SKEY  IS NOT NULL THEN 'Y' ELSE 'N' END,DIM_PARTY_CCP.f_qualified_ccp_flag,DIM_ORG_STRUCTURE_REG.F_REGULATORY_ENTITY_IND,CASE WHEN FCT_ENTITY_INFO.V_PARTY_ID = STG_OPTION_CONTRACTS.V_CUST_REF_CODE THEN 'Y' ELSE 'N' END,STG_OPTION_CONTRACTS.N_ACCRUED_INTEREST * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,COALESCE(FSI_PARTY_TYPE_SECTOR_RECLASS.N_BASEL_SECTOR_SKEY, FSI_CAP_INDUS_SECTOR_RECLASS.N_BASEL_SECTOR_SKEY),DIM_PARTY_CCP.n_party_skey,DIM_PARTY_CM.n_party_skey,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,CASE WHEN FSI_ACCT_MODELING_INFO.N_EFF_MATURITY IS NULL THEN (COALESCE(STG_OPTION_CONTRACTS.D_NEXT_REPRICE_DATE,STG_OPTION_CONTRACTS.D_MATURITY_DATE) -STG_OPTION_CONTRACTS.FIC_MIS_DATE)/365 ELSE FSI_ACCT_MODELING_INFO.N_EFF_MATURITY END,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_OPTION_CONTRACTS.N_OPTION_MTM_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,COALESCE(STG_OPTION_CONTRACTS.n_forex_haircut,0),FSI_ACCT_MODELING_INFO.N_STAGE_I_ALLOWANCES + FSI_ACCT_MODELING_INFO.N_STAGE_II_ALLOWANCES,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,COALESCE(STG_OPTION_CONTRACTS.N_INCURRED_CVA_AMOUNT,0) * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,GREATEST(DAYS_BETWEEN(STG_OPTION_CONTRACTS.FIC_MIS_DATE, GREATEST(STG_OPTION_CONTRACTS.D_MATURITY_DATE, COALESCE(STG_UNDERLYING_DTL.D_MATURITY_DATE,STG_OPTION_CONTRACTS.D_MATURITY_DATE)), STG_OPTION_CONTRACTS.V_DAY_COUNT_IND),10/(CASE WHEN FSI_RUN_PARAMETER.V_MPOR_CALC_BASIS = 'OPTDAY01' THEN DECODE(FSI_RUN_PARAMETER.V_NO_OF_BUSINESS_DAYS,'OPTDAY03',250,'OPTDAY04',252) ELSE 365 END)),CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,STG_OPTION_CONTRACTS.N_MARKET_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_OPTION_CONTRACTS.N_MORTGAGE_LENDING_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,COALESCE(DIM_NETTING_AGREEMENT.N_NETTING_AGREEMENT_SKEY, DUMMY_NETTING_AGREEMENT.N_NETTING_AGREEMENT_SKEY, 0),(CASE WHEN STG_OPTION_CONTRACTS.N_MV_PER_UNIT_RCY * STG_OPTION_CONTRACTS.N_CONTRACT_QUANTITY IS NULL THEN STG_OPTION_CONTRACTS.N_NOTIONAL_PRINCIPAL ELSE STG_OPTION_CONTRACTS.N_MV_PER_UNIT_RCY * STG_OPTION_CONTRACTS.N_CONTRACT_QUANTITY END) * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,(STG_OPTION_CONTRACTS.D_MATURITY_DATE -STG_OPTION_CONTRACTS.D_EFFECTIVE_DATE)/365,FSI_INSTR_VALUATION_DETAILS.N_OTHER_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DIM_PARENT_EXPOSURE.N_ACCT_SKEY,STG_OPTION_CONTRACTS.N_PROVISION_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_OPTION_CONTRACTS.N_LGD_PERCENT_PRE_CRM,(COALESCE(STG_OPTION_CONTRACTS.D_NEXT_REPRICE_DATE,STG_OPTION_CONTRACTS.D_MATURITY_DATE) -STG_OPTION_CONTRACTS.FIC_MIS_DATE)/365,'870',FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,STG_OPTION_CONTRACTS.N_STRIKE_RATE_PRICE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,to_date('20260331','YYYYMMDD') - STG_OPTION_CONTRACTS.D_LAST_EXERCISE_DATE,CASE WHEN STG_OPTION_CONTRACTS.FIC_MIS_DATE > LEAST(STG_OPTION_CONTRACTS.D_EFFECTIVE_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_OPTION_CONTRACTS.D_EFFECTIVE_DATE)) THEN 0 ELSE CASE WHEN DAYS_BETWEEN(STG_OPTION_CONTRACTS.FIC_MIS_DATE, LEAST(STG_OPTION_CONTRACTS.D_EFFECTIVE_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_OPTION_CONTRACTS.D_EFFECTIVE_DATE)), STG_OPTION_CONTRACTS.V_DAY_COUNT_IND) < 10 / 365 THEN 10 / 365 ELSE DAYS_BETWEEN(STG_OPTION_CONTRACTS.FIC_MIS_DATE, LEAST(STG_OPTION_CONTRACTS.D_EFFECTIVE_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_OPTION_CONTRACTS.D_EFFECTIVE_DATE)), STG_OPTION_CONTRACTS.V_DAY_COUNT_IND) END END,STG_OPTION_CONTRACTS.N_UNDERLYING_FORWARD_PRICE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,(STG_UNDERLYING_DTL.D_MATURITY_DATE - STG_OPTION_CONTRACTS.FIC_MIS_DATE) / 365,STG_OPTION_CONTRACTS.N_UNDRAWN_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_OPTION_CONTRACTS.N_UNPAID_PREMIUM * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_INSTR_VALUATION_DETAILS.N_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_OPTION_CONTRACTS.N_WRITE_OFF_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,'STG_OPTION_CONTRACTS',FSI_CAP_RUN_EXE_PARAMETERS.V_RCY_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_EXP_TREATED_AS_HIGH_RISK,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,to_char(FSI_ACCT_MODELING_INFO.N_ADJUSTED_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_DVA_AMOUNT),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER